// NURS 1000 Exam 4 — Pharmacology & Documentation (100 Questions)
const S={PH:"Pharmacology",DO:"Documentation & Informatics"};
const R=[
{id:1,s:"PH",t:"mc",q:"The mnemonic 'A Drug Must Exit' refers to which pharmacokinetic processes?",o:["Antagonism, Dependence, Metabolism, Excretion","Absorption, Distribution, Metabolism, Excretion","Administration, Dissolution, Modification, Elimination","Agonism, Distribution, Metabolism, Extraction"],c:[1],e:"ADME stands for Absorption, Distribution, Metabolism, and Excretion — the four phases of pharmacokinetics. The mnemonic 'A Drug Must Exit' helps recall these in order.",a:"B) Absorption, Distribution, Metabolism, Excretion",r:"Pharmacokinetics"},
{id:2,s:"PH",t:"mc",q:"A patient receives 500 mg of a medication with a half-life of 6 hours. How much drug remains in the body after 18 hours?",o:["125 mg","62.5 mg","31.25 mg","250 mg"],c:[1],e:"After each half-life, 50% of the drug is eliminated. 6hr=250mg, 12hr=125mg, 18hr=62.5mg. Three half-lives have passed.",a:"B) 62.5 mg",r:"Half-life"},
{id:3,s:"PH",t:"mc",q:"A nurse is prioritizing medication administration. Which patient should receive their medication FIRST?",o:["Patient with a headache requesting acetaminophen","Patient whose vancomycin trough level is due to be drawn in 30 minutes and the next dose is pending","Patient requesting a stool softener","Patient asking for a sleep aid at 2100"],c:[1],e:"The vancomycin trough must be drawn before the next dose is administered. Timing is critical to prevent toxicity. This is time-sensitive and takes priority over comfort medications.",a:"B) Patient whose vancomycin trough level is due to be drawn in 30 minutes and the next dose is pending",r:"Peak and Trough Levels"},
{id:4,s:"PH",t:"mc",q:"Which term describes the time it takes for a drug to reach its maximum blood concentration?",o:["Onset","Duration","Peak","Trough"],c:[2],e:"Peak refers to the highest blood concentration of a drug. Onset is when the drug begins working. Duration is how long the effect lasts. Trough is the lowest concentration before the next dose.",a:"C) Peak",r:"Pharmacokinetics"},
{id:5,s:"PH",t:"mc",q:"Pharmacodynamics is BEST described as:",o:["How the body absorbs, distributes, metabolizes, and excretes a drug","How the drug affects the body","The study of drug dosage calculations","The process of drug manufacturing and quality control"],c:[1],e:"Pharmacodynamics studies how drugs affect the body (mechanism of action, therapeutic effects). Pharmacokinetics is how the body affects the drug (ADME).",a:"B) How the drug affects the body",r:"Pharmacodynamics"},
{id:6,s:"PH",t:"mc",q:"A patient is prescribed lisinopril. Based on the drug suffix, this medication is classified as:",o:["A beta blocker","A loop diuretic","An ACE inhibitor","An opioid antagonist"],c:[2],e:"The suffix '-pril' identifies ACE inhibitors (e.g., lisinopril, enalapril, ramipril). '-olol' = beta blockers, '-mide' = loop diuretics.",a:"C) An ACE inhibitor",r:"Drug Suffixes"},
{id:7,s:"PH",t:"mc",q:"The nurse is triaging phone calls. Which patient report requires the MOST urgent intervention?",o:["Patient on warfarin reports eating a large salad with spinach","Patient on metoprolol reports a heart rate of 58 bpm","Patient on morphine reports pinpoint pupils and extreme drowsiness with a respiratory rate of 8","Patient on acetaminophen reports mild nausea"],c:[2],e:"Pinpoint pupils + respiratory depression (RR of 8) in a patient on morphine indicates opioid overdose — a life-threatening emergency requiring immediate naloxone. Remember the opioid triad: Pinpoint Pupils + Respiratory Depression + Unconsciousness → NALOXONE.",a:"C) Patient on morphine reports pinpoint pupils and extreme drowsiness with a respiratory rate of 8",r:"Opioid Overdose"},
{id:8,s:"PH",t:"mc",q:"N-acetyl-para-aminophenol is the __________ name for Tylenol.",o:["Generic","Trade","Chemical","Brand"],c:[2],e:"Chemical name = N-acetyl-para-aminophenol, Generic name = acetaminophen, Trade/Brand name = Tylenol. Chemical names describe the molecular structure.",a:"C) Chemical",r:"Drug Names"},
{id:9,s:"PH",t:"sata",q:"Which are included in the 6 Rights of medication administration? (Select all that apply)",o:["Right patient","Right dose","Right documentation","Right diagnosis","Right route","Right time"],c:[0,1,2,4,5],e:"The 6 Rights are: Right Patient, Right Drug, Right Dose, Right Route, Right Time, and Right Documentation. 'Right diagnosis' is not one of the 6 Rights.",a:"A, B, C, E, F) Right patient, dose, documentation, route, time",r:"6 Rights"},
{id:10,s:"PH",t:"mc",q:"A medication with a NARROW therapeutic index means:",o:["The drug has very few side effects","There is a small range between the effective dose and the toxic dose","The drug works slowly over a long duration","The drug can be given by any route"],c:[1],e:"A narrow therapeutic index means there is little difference between the therapeutic dose and the toxic dose. These drugs require careful monitoring (e.g., digoxin, warfarin, lithium).",a:"B) There is a small range between the effective dose and the toxic dose",r:"Therapeutic Index"},
{id:11,s:"PH",t:"mc",q:"When should a trough level be drawn?",o:["Immediately after the drug is administered","At the midpoint between two doses","Just before the next scheduled dose","Two hours after the peak level"],c:[2],e:"Trough level = lowest blood concentration of a drug, drawn just BEFORE the next scheduled dose to ensure the level hasn't dropped too low or remained too high.",a:"C) Just before the next scheduled dose",r:"Peak and Trough Levels"},
{id:12,s:"PH",t:"mc",q:"A patient taking warfarin should be instructed to avoid which food interaction?",o:["Bananas (high potassium)","Grapefruit juice","Consistent large amounts of dark green leafy vegetables","Dairy products"],c:[2],e:"Dark green leafy vegetables are high in vitamin K, which counteracts warfarin (a vitamin K inhibitor). Patients should maintain CONSISTENT vitamin K intake, not suddenly increase it. Grapefruit affects CYP3A4 drugs but warfarin's primary food concern is vitamin K.",a:"C) Consistent large amounts of dark green leafy vegetables",r:"Drug-Food Interactions"},
{id:13,s:"PH",t:"mc",q:"The nurse is caring for four patients. Which patient situation requires the nurse to intervene FIRST?",o:["A patient on aspirin who reports ringing in the ears","A patient on acetaminophen with mild stomach upset","A patient requesting their scheduled multivitamin","A patient asking about their discharge medications"],c:[0],e:"Tinnitus (ringing in the ears) is an adverse reaction to aspirin that may indicate toxicity. This requires immediate assessment and potential intervention before addressing routine needs.",a:"A) A patient on aspirin who reports ringing in the ears",r:"Aspirin Adverse Reactions"},
{id:14,s:"PH",t:"mc",q:"Naloxone (Narcan) is classified as a(n):",o:["Opioid agonist","Opioid antagonist","Anticoagulant","Antiplatelet agent"],c:[1],e:"Naloxone is an opioid ANTAGONIST — it reverses the effects of opioids by blocking opioid receptors. It is the antidote for opioid overdose. Morphine is an opioid agonist.",a:"B) Opioid antagonist",r:"Key Drugs"},
{id:15,s:"PH",t:"tf",q:"True or False: A drug with a short half-life requires MORE frequent dosing than a drug with a long half-life.",o:["True","False"],c:[0],e:"True. Short half-life = drug is eliminated quickly, so it must be dosed more frequently to maintain therapeutic levels. Long half-life = drug stays in the body longer, requiring less frequent dosing.",a:"A) True",r:"Half-life"},
{id:16,s:"PH",t:"mc",q:"A patient is experiencing anaphylaxis after receiving a new medication. Which assessment finding does the nurse expect?",o:["Bradycardia and hypertension","Swelling of the airway and difficulty breathing","Pinpoint pupils and sedation","Tinnitus and dizziness"],c:[1],e:"Anaphylaxis is a severe allergic reaction characterized by airway swelling (angioedema), difficulty breathing, hypotension, and urticaria. This is a medical emergency requiring epinephrine.",a:"B) Swelling of the airway and difficulty breathing",r:"Adverse Reactions"},
{id:17,s:"PH",t:"mc",q:"Which drug schedule has the HIGHEST potential for abuse and NO accepted medical use?",o:["Schedule II","Schedule III","Schedule V","Schedule I"],c:[3],e:"Schedule I drugs have the highest abuse potential and NO accepted medical use in the US (e.g., heroin, LSD). Schedule II has high abuse potential but accepted medical uses (e.g., morphine, oxycodone).",a:"D) Schedule I",r:"Controlled Substances"},
{id:18,s:"PH",t:"mc",q:"The antidote for warfarin toxicity is:",o:["Protamine sulfate","Naloxone","Vitamin K","Flumazenil"],c:[2],e:"Vitamin K is the antidote for warfarin (a vitamin K inhibitor). Protamine sulfate is the antidote for heparin. Naloxone reverses opioids. Flumazenil reverses benzodiazepines.",a:"C) Vitamin K",r:"Key Drugs"},
{id:19,s:"PH",t:"mc",q:"Grapefruit juice can be dangerous with certain medications because it:",o:["Increases stomach acid production","Inhibits CYP3A4 enzyme, slowing drug metabolism","Increases renal excretion of the drug","Binds to the drug and prevents absorption"],c:[1],e:"Grapefruit juice inhibits the CYP3A4 enzyme in the liver and intestines, which slows drug metabolism. This causes drug levels to build up, potentially reaching toxic levels. Remember: 'Grapefruit is NOT your friend.'",a:"B) Inhibits CYP3A4 enzyme, slowing drug metabolism",r:"Drug-Food Interactions"},
{id:20,s:"PH",t:"sata",q:"Which findings indicate a possible opioid overdose? (Select all that apply)",o:["Dilated pupils","Pinpoint pupils","Respiratory rate of 8 breaths/min","Hypertension","Unconsciousness"],c:[1,2,4],e:"The opioid triad: Pinpoint Pupils + Respiratory Depression + Unconsciousness → NALOXONE. Dilated pupils and hypertension are NOT characteristic of opioid overdose.",a:"B, C, E) Pinpoint pupils, respiratory rate of 8, unconsciousness",r:"Opioid Overdose"},
{id:21,s:"PH",t:"mc",q:"A drug that produces a response by binding to and activating a receptor is called a(n):",o:["Antagonist","Agonist","Inhibitor","Catalyst"],c:[1],e:"An agonist binds to a receptor and activates it, producing a physiological response. An antagonist binds to a receptor and BLOCKS it, preventing a response. Morphine is an opioid agonist.",a:"B) Agonist",r:"Pharmacodynamics"},
{id:22,s:"PH",t:"mc",q:"Which medication suffix indicates a beta blocker?",o:["-pril","-mide","-olol","-statin"],c:[2],e:"Drug suffix '-olol' = beta blockers (e.g., metoprolol, atenolol, propranolol). '-pril' = ACE inhibitors. '-mide' = loop diuretics. '-statin' = cholesterol-lowering agents.",a:"C) -olol",r:"Drug Suffixes"},
{id:23,s:"PH",t:"mc",q:"The nurse is prioritizing care for four patients. Which situation should the nurse address FIRST?",o:["A patient who needs teaching about a new prescription","A patient whose IV antibiotic is scheduled in 15 minutes","A patient experiencing a severe allergic reaction with facial swelling and wheezing","A patient requesting pain medication rated 4/10"],c:[2],e:"A severe allergic reaction (anaphylaxis) with airway compromise is life-threatening and requires immediate intervention (epinephrine). Use the ABCs — airway is always priority.",a:"C) A patient experiencing a severe allergic reaction with facial swelling and wheezing",r:"Adverse Reactions"},
{id:24,s:"PH",t:"mc",q:"Which factor increases the risk of drug toxicity in older adults?",o:["Faster hepatic metabolism","Increased renal clearance","Decreased liver and kidney function","Higher percentage of body water"],c:[2],e:"Older adults have decreased liver metabolism and reduced renal function, which slows drug clearance and increases the risk of drug accumulation and toxicity. Age is an important precaution.",a:"C) Decreased liver and kidney function",r:"Precautions"},
{id:25,s:"PH",t:"mc",q:"A patient develops tolerance to a medication. This means:",o:["The drug has accumulated to toxic levels","Larger doses are needed to achieve the same therapeutic effect","The patient is allergic to the medication","The drug has reached its peak concentration"],c:[1],e:"Tolerance occurs when the body adapts to a drug over time, requiring increasingly larger doses to achieve the same effect. This is different from drug toxicity or allergy.",a:"B) Larger doses are needed to achieve the same therapeutic effect",r:"Adverse Reactions"},
{id:26,s:"PH",t:"order",q:"Place the pharmacokinetic processes in the correct order:",o:["Absorption","Distribution","Metabolism","Excretion"],c:[0,1,2,3],e:"ADME — 'A Drug Must Exit': Absorption (drug enters bloodstream) → Distribution (drug travels to tissues) → Metabolism (drug is broken down, primarily in liver) → Excretion (drug is eliminated, primarily by kidneys).",a:"Absorption → Distribution → Metabolism → Excretion",r:"Pharmacokinetics"},
{id:27,s:"PH",t:"mc",q:"Which statement by a patient taking warfarin indicates a need for further teaching?",o:["'I will have my blood levels checked regularly.'","'I should eat consistent amounts of green vegetables.'","'I will take extra vitamin K supplements to stay healthy.'","'I need to report any unusual bruising to my doctor.'"],c:[2],e:"Taking extra vitamin K supplements would counteract warfarin's anticoagulant effect. Patients should maintain a CONSISTENT vitamin K intake, not increase it. The other statements show understanding.",a:"C) 'I will take extra vitamin K supplements to stay healthy.'",r:"Drug-Food Interactions"},
{id:28,s:"PH",t:"mc",q:"The primary organ responsible for drug metabolism is the:",o:["Kidney","Liver","Lungs","Small intestine"],c:[1],e:"The liver is the primary organ for drug metabolism (biotransformation). The kidneys are primarily responsible for drug excretion. First-pass metabolism occurs in the liver.",a:"B) Liver",r:"Pharmacokinetics"},
{id:29,s:"PH",t:"mc",q:"The antidote for heparin overdose is:",o:["Vitamin K","Naloxone","Protamine sulfate","Acetylcysteine"],c:[2],e:"Protamine sulfate is the antidote for heparin. Vitamin K is the antidote for warfarin. Naloxone reverses opioids. Acetylcysteine is the antidote for acetaminophen overdose.",a:"C) Protamine sulfate",r:"Key Drugs"},
{id:30,s:"PH",t:"tf",q:"True or False: Morphine is an opioid antagonist used to reverse respiratory depression.",o:["True","False"],c:[1],e:"False. Morphine is an opioid AGONIST (it activates opioid receptors and can CAUSE respiratory depression). NALOXONE is the opioid antagonist used to reverse opioid-induced respiratory depression.",a:"B) False",r:"Key Drugs"},
{id:31,s:"PH",t:"mc",q:"A nurse is triaging patients in the emergency department. Which patient needs to be seen FIRST?",o:["A patient with a sprained ankle requesting ibuprofen","A patient with a blood glucose of 45 mg/dL who appears confused","A patient with mild seasonal allergies requesting antihistamines","A patient with a urinary tract infection requesting antibiotics"],c:[1],e:"A blood glucose of 45 mg/dL with confusion is hypoglycemia — a potentially life-threatening emergency requiring immediate glucose administration. The other situations are not immediately life-threatening.",a:"B) A patient with a blood glucose of 45 mg/dL who appears confused",r:"Triage"},
{id:32,s:"PH",t:"mc",q:"A cumulative drug effect occurs when:",o:["The drug is metabolized too quickly","The drug accumulates in the body faster than it can be eliminated","The patient develops an allergy to the drug","Two drugs cancel each other's effects"],c:[1],e:"A cumulative effect happens when a drug builds up in the body because it is administered faster than the body can metabolize and excrete it, potentially leading to toxicity.",a:"B) The drug accumulates in the body faster than it can be eliminated",r:"Adverse Reactions"},
{id:33,s:"PH",t:"sata",q:"Which precautions should the nurse consider before administering a medication? (Select all that apply)",o:["Patient's age","Pregnancy status","Known drug allergies","Patient's favorite color","Chronic health conditions"],c:[0,1,2,4],e:"Important medication precautions include age, pregnancy/lactation status, known allergies, and chronic conditions (liver/kidney disease). The patient's favorite color is irrelevant to medication safety.",a:"A, B, C, E) Age, pregnancy status, drug allergies, chronic conditions",r:"Precautions"},
{id:34,s:"PH",t:"mc",q:"Which drug interaction occurs when one drug increases the effect of another drug?",o:["Antagonistic interaction","Synergistic/potentiating interaction","Idiosyncratic reaction","Paradoxical reaction"],c:[1],e:"A synergistic or potentiating interaction occurs when one drug increases the effect of another (e.g., taking two CNS depressants together). Antagonistic interactions decrease effects.",a:"B) Synergistic/potentiating interaction",r:"Drug-Drug Interactions"},
{id:35,s:"PH",t:"mc",q:"A patient asks why they cannot have grapefruit juice with their statin medication. The nurse's BEST response is:",o:["'Grapefruit makes the drug less effective by increasing excretion.'","'Grapefruit inhibits an enzyme that breaks down the drug, which could cause dangerous drug buildup.'","'Grapefruit destroys the medication in your stomach.'","'Grapefruit has no real effect; it's just a precaution.'"],c:[1],e:"Grapefruit juice inhibits CYP3A4, the enzyme responsible for metabolizing many drugs including statins. This leads to higher-than-intended drug levels, increasing the risk of side effects and toxicity.",a:"B) 'Grapefruit inhibits an enzyme that breaks down the drug, which could cause dangerous drug buildup.'",r:"Drug-Food Interactions"},
{id:36,s:"PH",t:"fib",q:"The generic name for Tylenol is __________.",o:[],c:["acetaminophen"],e:"Acetaminophen is the generic name. Chemical name = N-acetyl-para-aminophenol. Trade/Brand name = Tylenol. Nurses typically use the generic name.",a:"acetaminophen",r:"Drug Names"},
{id:37,s:"PH",t:"mc",q:"Which route of administration typically has the FASTEST onset of action?",o:["Oral","Subcutaneous","Intravenous","Intramuscular"],c:[2],e:"Intravenous (IV) has the fastest onset because the drug is delivered directly into the bloodstream, bypassing absorption. Oral is generally the slowest due to the need for GI absorption and first-pass metabolism.",a:"C) Intravenous",r:"Pharmacokinetics"},
{id:38,s:"PH",t:"mc",q:"The nurse receives orders for four patients. Which order should the nurse question?",o:["Acetaminophen 650 mg PO every 6 hours PRN for fever","Morphine 2 mg IV push every 4 hours PRN for pain","Naloxone 0.4 mg IV for a patient with a respiratory rate of 20","Warfarin 5 mg PO daily with INR monitoring"],c:[2],e:"Naloxone is an opioid antagonist given for opioid overdose with respiratory depression. A respiratory rate of 20 is NORMAL (12-20). There is no indication for naloxone, so this order should be questioned.",a:"C) Naloxone 0.4 mg IV for a patient with a respiratory rate of 20",r:"Key Drugs"},
{id:39,s:"PH",t:"mc",q:"A Schedule II controlled substance differs from Schedule V in that Schedule II:",o:["Has no medical use","Has a lower potential for abuse","Has a higher potential for abuse with strict prescribing rules","Can be purchased over the counter"],c:[2],e:"Schedule II drugs have a HIGH abuse potential but accepted medical use with severe restrictions (e.g., morphine, oxycodone). Schedule V has the LOWEST abuse potential (e.g., cough preparations with small amounts of codeine).",a:"C) Has a higher potential for abuse with strict prescribing rules",r:"Controlled Substances"},
{id:40,s:"PH",t:"mc",q:"The nurse is caring for a patient receiving vancomycin. Which lab value is MOST important to monitor?",o:["Blood glucose","Hemoglobin A1C","Trough level","Platelet count"],c:[2],e:"Vancomycin has a narrow therapeutic index. Trough levels must be monitored to ensure therapeutic effectiveness while preventing toxicity (nephrotoxicity, ototoxicity). Trough is drawn just before the next dose.",a:"C) Trough level",r:"Peak and Trough Levels"},
{id:41,s:"DO",t:"mc",q:"In SOAP charting, the 'S' stands for:",o:["Summary","Subjective","Systems","Status"],c:[1],e:"SOAP = Subjective, Objective, Assessment, Plan. Subjective data is what the patient tells you (symptoms, feelings, complaints). Remember: 'Subjective Objective Assessment Plan.'",a:"B) Subjective",r:"SOAP Charting"},
{id:42,s:"DO",t:"mc",q:"A nurse makes an error in a paper medical record. What is the CORRECT way to handle this?",o:["Use white-out to cover the error and rewrite","Erase the entry and start over","Draw a single line through the error, write 'error,' and add initials, date, and time","Remove the page and replace it with a corrected version"],c:[2],e:"Correct documentation errors by drawing a single line through the entry, writing 'error,' and adding your initials, date, and time. NEVER erase, use white-out, or remove pages from the medical record.",a:"C) Draw a single line through the error, write 'error,' and add initials, date, and time",r:"Correcting Errors"},
{id:43,s:"DO",t:"mc",q:"The PIE charting format stands for:",o:["Patient, Intervention, Evaluation","Problem, Intervention, Evaluation","Plan, Implementation, Evaluation","Problem, Identification, Examination"],c:[1],e:"PIE = Problem, Intervention, Evaluation. This format focuses on identifying patient problems, the nursing interventions performed, and evaluation of the outcomes.",a:"B) Problem, Intervention, Evaluation",r:"PIE Charting"},
{id:44,s:"DO",t:"mc",q:"Which documentation system records ONLY abnormal or unexpected findings?",o:["SOAP charting","Narrative charting","Charting by exception","Focus charting"],c:[2],e:"Charting by exception documents only abnormal or unexpected findings, using pre-established norms/standards. Normal findings are assumed unless otherwise documented. This saves time but requires clear protocols.",a:"C) Charting by exception",r:"Charting by Exception"},
{id:45,s:"DO",t:"mc",q:"HIPAA is a federal law that primarily protects:",o:["Nurse staffing ratios","Patient health information (PHI)","Hospital accreditation standards","Medication formulary lists"],c:[1],e:"HIPAA (Health Insurance Portability and Accountability Act) is a federal law that protects Protected Health Information (PHI). It sets standards for privacy and security of patient data.",a:"B) Patient health information (PHI)",r:"HIPAA"},
{id:46,s:"DO",t:"mc",q:"Which charting format uses Data, Action, Response?",o:["SOAP","PIE","DAR (Focus charting)","FACT"],c:[2],e:"DAR = Data, Action, Response — used in Focus charting. Data = subjective/objective findings. Action = nursing interventions. Response = patient's response to interventions.",a:"C) DAR (Focus charting)",r:"DAR Charting"},
{id:47,s:"DO",t:"sata",q:"Which actions are appropriate when correcting a documentation error in a paper chart? (Select all that apply)",o:["Draw a single line through the error","Write 'error' near the correction","Use white-out to cover the mistake","Add initials, date, and time","Remove the page and rewrite it"],c:[0,1,3],e:"Correct errors: single line through, write 'error,' add initials/date/time. NEVER use white-out, erase, or remove pages. These are legal documents.",a:"A, B, D) Single line, write 'error,' add initials/date/time",r:"Correcting Errors"},
{id:48,s:"DO",t:"mc",q:"The nurse is prioritizing documentation tasks. Which should be completed FIRST?",o:["Writing a narrative note about a patient's lunch preferences","Documenting the administration of a high-alert medication","Filing a patient satisfaction survey","Updating the whiteboard with the patient's nurse assignment"],c:[1],e:"Documenting high-alert medication administration is a safety priority. If not documented, another nurse may inadvertently re-administer the medication. Right documentation is one of the 6 Rights.",a:"B) Documenting the administration of a high-alert medication",r:"Documentation Priority"},
{id:49,s:"DO",t:"mc",q:"In the SBAR handoff communication format, 'B' stands for:",o:["Baseline","Background","Brief","Bilateral"],c:[1],e:"SBAR = Situation, Background, Assessment, Recommendation. Background includes pertinent medical history and context. SBAR is used for standardized handoff communication between healthcare providers.",a:"B) Background",r:"SBAR"},
{id:50,s:"DO",t:"mc",q:"Which type of medical record organizes documentation by discipline (nursing, medicine, therapy)?",o:["Problem-oriented medical record","Source-oriented medical record","Electronic health record","Focus charting record"],c:[1],e:"Source-oriented medical records are the traditional format where each discipline (nursing, medicine, therapy, etc.) documents in its own section. Problem-oriented records organize by patient problems.",a:"B) Source-oriented medical record",r:"Medical Records"},
{id:51,s:"DO",t:"tf",q:"True or False: Incident reports should be documented in the patient's medical chart.",o:["True","False"],c:[1],e:"False. Incident reports are internal documents used for quality improvement. They should NOT be placed in or referenced in the patient's medical chart. They must be factual and objective.",a:"B) False",r:"Incident Reports"},
{id:52,s:"DO",t:"mc",q:"Which is the PRIMARY advantage of electronic health records (EHR) over paper charts?",o:["Lower cost to implement","Real-time access to patient data and clinical alerts","No training required for staff","Immune to all types of errors"],c:[1],e:"EHRs provide real-time access to patient data, clinical decision support alerts, and eliminate issues with illegible handwriting. However, they have disadvantages like system downtime and implementation costs.",a:"B) Real-time access to patient data and clinical alerts",r:"Electronic Health Records"},
{id:53,s:"DO",t:"mc",q:"The nurse receives a verbal order from the physician during an emergency. The nurse's FIRST action is to:",o:["Document the order after the emergency is over","Repeat the order back to the physician to verify accuracy","Have another nurse witness the verbal communication","Ask the physician to enter it in the computer first"],c:[1],e:"Verbal orders should only be accepted in emergencies. The nurse must READ BACK and VERIFY the order with the prescriber for accuracy. The 6 Rights still apply to verbal orders.",a:"B) Repeat the order back to the physician to verify accuracy",r:"Verbal Orders"},
{id:54,s:"DO",t:"mc",q:"Nursing informatics is BEST defined as:",o:["Using social media to communicate with patients","The integration of nursing science with information technology","Filing paper charts in the correct order","Scheduling nurse shifts using a computer"],c:[1],e:"Nursing informatics combines nursing science, information science, and technology to manage and communicate data, information, and knowledge in nursing practice.",a:"B) The integration of nursing science with information technology",r:"Nursing Informatics"},
{id:55,s:"DO",t:"mc",q:"The FACT documentation system stands for:",o:["Frequent, Accurate, Charted, Therapeutic","Factual, Accurate, Complete, Timely","Focused, Assessment, Comprehensive, Treatment","Finding, Action, Communication, Treatment"],c:[1],e:"FACT = Factual, Accurate, Complete, Timely. This mnemonic reminds nurses that all documentation must meet these four criteria to be legally sound and clinically useful.",a:"B) Factual, Accurate, Complete, Timely",r:"FACT Charting"},
{id:56,s:"DO",t:"mc",q:"A new nurse asks about the purpose of barcode scanning during medication administration. The BEST response is:",o:["'It replaces the need to check the patient's armband.'","'It improves medication safety by verifying the right patient and right drug.'","'It is only used for billing purposes.'","'It eliminates the need for the 6 Rights.'"],c:[1],e:"Barcode scanning verifies patient identity and medication accuracy at the point of care, improving safety and documentation. It does NOT replace the 6 Rights — it supports them.",a:"B) 'It improves medication safety by verifying the right patient and right drug.'",r:"Barcode Scanning"},
{id:57,s:"DO",t:"mc",q:"Which component of a problem-oriented medical record organizes patient concerns into an active list?",o:["Database","Problem list","Plan of care","Progress notes"],c:[1],e:"A problem-oriented medical record has four components: Database → Problem List → Plan → Progress Notes. The problem list organizes identified patient concerns that need to be addressed.",a:"B) Problem list",r:"Medical Records"},
{id:58,s:"DO",t:"sata",q:"Which statements about verbal orders are correct? (Select all that apply)",o:["They should be used routinely to save time","They should be reserved for emergency situations","The nurse should read back the order to verify","The nurse should apply the 6 Rights","They never need to be co-signed by the prescriber"],c:[1,2,3],e:"Verbal orders should be used in emergencies only, the nurse must read back and verify, and the 6 Rights apply. They must be co-signed by the prescriber as soon as possible. They should NOT be routine.",a:"B, C, D) Emergency only, read back, apply 6 Rights",r:"Verbal Orders"},
{id:59,s:"DO",t:"mc",q:"The PRIMARY disadvantage of electronic health records is:",o:["They cannot store diagnostic images","System downtime can prevent access to patient data","They do not support interdisciplinary communication","They increase handwriting errors"],c:[1],e:"The main disadvantage of EHRs is that system downtime (power outages, server crashes, cyber attacks) can prevent access to patient records. Facilities need backup plans for downtime.",a:"B) System downtime can prevent access to patient data",r:"Electronic Health Records"},
{id:60,s:"DO",t:"tf",q:"True or False: It is acceptable to use white-out to correct an error in a paper medical record.",o:["True","False"],c:[1],e:"False. NEVER use white-out, erase, or remove pages from a medical record. The correct method is: single line through the error, write 'error,' add initials, date, and time.",a:"B) False",r:"Correcting Errors"},
{id:61,s:"DO",t:"mc",q:"An incident report should include which type of information?",o:["The nurse's opinion about who was at fault","Factual, objective description of what occurred","Speculation about why the incident happened","A copy of the patient's full medical history"],c:[1],e:"Incident reports must contain factual, objective information about what occurred. They should NOT include opinions, blame, or speculation. They are used for quality improvement, not punishment.",a:"B) Factual, objective description of what occurred",r:"Incident Reports"},
{id:62,s:"DO",t:"order",q:"Arrange the components of SOAP charting in the correct order:",o:["Subjective","Objective","Assessment","Plan"],c:[0,1,2,3],e:"SOAP = Subjective (patient's reported symptoms) → Objective (measurable data, vital signs) → Assessment (nursing judgment/diagnosis) → Plan (interventions and next steps).",a:"Subjective → Objective → Assessment → Plan",r:"SOAP Charting"},
{id:63,s:"DO",t:"mc",q:"Which technology allows healthcare providers to monitor patients remotely?",o:["Barcode scanning","Telehealth and remote monitoring","Source-oriented charting","Problem-oriented medical records"],c:[1],e:"Telehealth/telemedicine and remote monitoring technology allow providers to assess and monitor patients from a distance, improving access to care especially for rural or homebound patients.",a:"B) Telehealth and remote monitoring",r:"Telehealth"},
{id:64,s:"DO",t:"mc",q:"The nurse is delegating documentation tasks. Which task can the nurse delegate to unlicensed assistive personnel (UAP)?",o:["Writing a nursing assessment in the patient's chart","Documenting vital signs taken by the UAP","Charting medication administration","Writing the nursing care plan"],c:[1],e:"UAPs can document tasks they performed, such as vital signs they measured. Nursing assessments, medication documentation, and care plans require a licensed nurse and cannot be delegated.",a:"B) Documenting vital signs taken by the UAP",r:"Documentation"},
{id:65,s:"DO",t:"mc",q:"In focus charting (DAR), the 'A' stands for:",o:["Assessment","Action","Analysis","Admission"],c:[1],e:"DAR = Data, Action, Response. 'A' stands for Action — the nursing interventions performed in response to the patient data collected. Do not confuse with the 'A' in SOAP (Assessment).",a:"B) Action",r:"DAR Charting"},
{id:66,s:"PH",t:"mc",q:"A nurse is preparing to administer medications to four patients. Which patient should the nurse see FIRST?",o:["A patient whose morning vitamins are due","A patient with chest pain requesting nitroglycerin","A patient requesting a PRN laxative","A patient due for a scheduled blood pressure medication in 30 minutes"],c:[1],e:"Chest pain with a request for nitroglycerin is an urgent, potentially life-threatening situation requiring immediate intervention. Pain medications for acute cardiac events take priority over routine meds.",a:"B) A patient with chest pain requesting nitroglycerin",r:"Triage"},
{id:67,s:"PH",t:"mc",q:"Which statement BEST describes the difference between drug onset and drug duration?",o:["Onset is the maximum effect; duration is the minimum effect","Onset is when the drug begins working; duration is how long the effect lasts","Onset is the route of administration; duration is the half-life","Onset is the trough level; duration is the peak level"],c:[1],e:"Onset = when the drug begins to take effect. Peak = maximum effect. Duration = total length of time the drug produces its effect. These are key pharmacokinetic parameters.",a:"B) Onset is when the drug begins working; duration is how long the effect lasts",r:"Pharmacokinetics"},
{id:68,s:"PH",t:"sata",q:"Which drug-food interactions should the nurse teach patients about? (Select all that apply)",o:["Grapefruit juice with statins","Dark green vegetables with warfarin","Calcium-rich foods with certain antibiotics","Wine with CNS depressants","Bananas with ACE inhibitors"],c:[0,1,2,3],e:"All listed except bananas with ACE inhibitors are well-known drug-food interactions. Grapefruit inhibits CYP3A4, vitamin K counteracts warfarin, calcium chelates antibiotics like tetracycline, and alcohol potentiates CNS depressants.",a:"A, B, C, D) Grapefruit with statins, greens with warfarin, calcium with antibiotics, wine with CNS depressants",r:"Drug-Food Interactions"},
{id:69,s:"PH",t:"mc",q:"A patient on a continuous morphine drip has a respiratory rate of 6 and is unresponsive. The nurse should FIRST:",o:["Increase the IV fluid rate","Administer naloxone as ordered","Reposition the patient","Call the family"],c:[1],e:"Respiratory rate of 6 with unresponsiveness in a patient on morphine indicates opioid overdose. Naloxone (the opioid antagonist) should be administered immediately to reverse respiratory depression. Remember: Pinpoint Pupils + Respiratory Depression + Unconsciousness → NALOXONE.",a:"B) Administer naloxone as ordered",r:"Opioid Overdose"},
{id:70,s:"PH",t:"mc",q:"The therapeutic effect of a drug refers to:",o:["Any side effect the drug produces","The desired, intended outcome of the drug","The toxic level of the drug in the blood","The time it takes for the drug to be excreted"],c:[1],e:"The therapeutic effect is the desired, intended outcome of a drug (e.g., pain relief from an analgesic, blood pressure reduction from an antihypertensive). Side effects are unintended.",a:"B) The desired, intended outcome of the drug",r:"Therapeutic Effect"},
{id:71,s:"PH",t:"fib",q:"The suffix '-olol' identifies drugs classified as __________.",o:[],c:["beta blockers"],e:"The suffix '-olol' identifies beta blockers (e.g., metoprolol, atenolol, propranolol). These medications block beta-adrenergic receptors, reducing heart rate and blood pressure.",a:"beta blockers",r:"Drug Suffixes"},
{id:72,s:"PH",t:"mc",q:"Which nursing action is MOST important before administering any medication?",o:["Check the patient's insurance coverage","Verify the patient's identity using two identifiers","Ask the patient if they want the medication","Check the medication's expiration date only"],c:[1],e:"Verifying patient identity using two identifiers (e.g., name and date of birth) is the first and most critical step — Right Patient is the foundation of the 6 Rights of medication administration.",a:"B) Verify the patient's identity using two identifiers",r:"6 Rights"},
{id:73,s:"PH",t:"mc",q:"A nurse is caring for a patient taking furosemide. Based on the suffix '-mide,' this drug is classified as a:",o:["Beta blocker","ACE inhibitor","Loop diuretic","Calcium channel blocker"],c:[2],e:"The suffix '-mide' identifies loop diuretics (e.g., furosemide/Lasix, bumetanide). Loop diuretics act on the loop of Henle in the kidneys to promote fluid excretion.",a:"C) Loop diuretic",r:"Drug Suffixes"},
{id:74,s:"PH",t:"mc",q:"A pregnant patient asks about taking medications during pregnancy. The nurse's BEST response is:",o:["'All medications are safe during pregnancy.'","'You should never take any medications while pregnant.'","'Some medications can harm the fetus, so all medications must be evaluated by your provider.'","'Only over-the-counter medications are safe.'"],c:[2],e:"Pregnancy is an important precaution. Many drugs can cross the placenta and harm the fetus. All medications must be carefully evaluated by the healthcare provider for risk vs. benefit during pregnancy.",a:"C) 'Some medications can harm the fetus, so all medications must be evaluated by your provider.'",r:"Precautions"},
{id:75,s:"PH",t:"tf",q:"True or False: The trough level of a medication is drawn immediately after the drug is administered.",o:["True","False"],c:[1],e:"False. The trough level is drawn just BEFORE the next scheduled dose, when the drug concentration is at its lowest point. Drawing it after administration would give an inaccurate, elevated reading.",a:"B) False",r:"Peak and Trough Levels"},
{id:76,s:"PH",t:"mc",q:"Which assessment finding would the nurse report IMMEDIATELY in a patient taking aspirin?",o:["Mild headache","Ringing in the ears (tinnitus)","Slight drowsiness","Decreased appetite"],c:[1],e:"Tinnitus (ringing in the ears) is a significant adverse reaction to aspirin and may indicate aspirin toxicity. This should be reported immediately. Other findings are less concerning.",a:"B) Ringing in the ears (tinnitus)",r:"Aspirin Adverse Reactions"},
{id:77,s:"PH",t:"mc",q:"A drug-drug interaction that DECREASES the effectiveness of one or both drugs is called:",o:["Synergistic","Potentiating","Antagonistic","Additive"],c:[2],e:"An antagonistic drug interaction occurs when one drug decreases or blocks the effect of another drug. Synergistic and potentiating interactions INCREASE effects. Additive interactions combine equal effects.",a:"C) Antagonistic",r:"Drug-Drug Interactions"},
{id:78,s:"PH",t:"sata",q:"Which patients require special precautions when administering medications? (Select all that apply)",o:["A 2-year-old child","A healthy 30-year-old adult","A 78-year-old with renal impairment","A pregnant woman in her first trimester","A patient with severe liver disease"],c:[0,2,3,4],e:"Special precautions are needed for pediatric patients (immature organ systems), elderly with organ impairment, pregnant patients (fetal risk), and those with liver/kidney disease (altered metabolism and excretion).",a:"A, C, D, E) 2-year-old, elderly with renal impairment, pregnant woman, patient with liver disease",r:"Precautions"},
{id:79,s:"PH",t:"mc",q:"Which statement about the therapeutic index is CORRECT?",o:["A wide therapeutic index means the drug is very dangerous","A narrow therapeutic index requires frequent blood level monitoring","The therapeutic index measures how fast a drug is absorbed","The therapeutic index determines the drug's route of administration"],c:[1],e:"A narrow therapeutic index means there is a small margin between the effective dose and the toxic dose, requiring careful monitoring of blood levels (e.g., digoxin, warfarin, vancomycin, lithium).",a:"B) A narrow therapeutic index requires frequent blood level monitoring",r:"Therapeutic Index"},
{id:80,s:"PH",t:"order",q:"Arrange the controlled substance schedules from HIGHEST to LOWEST abuse potential:",o:["Schedule I","Schedule II","Schedule III","Schedule IV","Schedule V"],c:[0,1,2,3,4],e:"Schedule I = highest abuse potential, no accepted medical use. Schedule V = lowest abuse potential. As the schedule number increases, abuse potential decreases and medical use is more accepted.",a:"Schedule I → II → III → IV → V",r:"Controlled Substances"},
{id:81,s:"DO",t:"mc",q:"The nurse is reviewing documentation systems. Which system focuses on documenting abnormal findings only, assuming all normals are within standards?",o:["Narrative charting","SOAP notes","Charting by exception","Source-oriented records"],c:[2],e:"Charting by exception (CBE) is based on the premise that all standards are met unless documented otherwise. Only abnormal or significant findings are charted, saving time while maintaining thorough records.",a:"C) Charting by exception",r:"Charting by Exception"},
{id:82,s:"DO",t:"mc",q:"A nurse discovers a medication error has occurred. After ensuring patient safety, which is the NEXT priority?",o:["Notify the charge nurse at the end of the shift","Complete an incident report with factual, objective information","Discuss the error with other nurses on the unit","Document the incident report in the patient's chart"],c:[1],e:"After ensuring patient safety, an incident report with factual, objective details must be completed promptly. It should NOT be placed in the chart or discussed casually. The charge nurse and provider should be notified timely.",a:"B) Complete an incident report with factual, objective information",r:"Incident Reports"},
{id:83,s:"DO",t:"tf",q:"True or False: SBAR stands for Situation, Background, Assessment, Recommendation.",o:["True","False"],c:[0],e:"True. SBAR is a standardized communication tool used for handoff reports: Situation (what's happening), Background (clinical history), Assessment (what you think), Recommendation (what you suggest).",a:"A) True",r:"SBAR"},
{id:84,s:"DO",t:"mc",q:"Which is an example of SUBJECTIVE data in a SOAP note?",o:["Blood pressure 130/85 mmHg","The patient states, 'I feel dizzy and nauseous.'","White blood cell count of 12,000","Temperature of 101.2°F"],c:[1],e:"Subjective data is what the PATIENT reports — their symptoms, feelings, and perceptions. Objective data is measurable and observable (vital signs, lab values). Patient statements = Subjective.",a:"B) The patient states, 'I feel dizzy and nauseous.'",r:"SOAP Charting"},
{id:85,s:"DO",t:"mc",q:"A problem-oriented medical record follows which organizational sequence?",o:["Problem → Data → Assessment → Plan","Subjective → Objective → Assessment → Plan","Database → Problem List → Plan → Progress Notes","Data → Action → Response"],c:[2],e:"Problem-oriented medical records (POMR) are organized: Database (initial data) → Problem List (identified issues) → Plan (for each problem) → Progress Notes (ongoing documentation).",a:"C) Database → Problem List → Plan → Progress Notes",r:"Medical Records"},
{id:86,s:"DO",t:"sata",q:"Which are benefits of electronic health records (EHR)? (Select all that apply)",o:["Real-time access to patient information","Clinical decision support alerts","Elimination of handwritten documentation errors","Guaranteed 100% uptime with no system failures","Improved interdisciplinary communication"],c:[0,1,2,4],e:"EHR benefits include real-time access, clinical alerts, eliminating illegible handwriting, and improved communication. No system has 100% uptime — downtime is a recognized disadvantage.",a:"A, B, C, E) Real-time access, alerts, eliminates handwriting errors, improved communication",r:"Electronic Health Records"},
{id:87,s:"DO",t:"mc",q:"The nurse is triaging documentation tasks at the end of a busy shift. Which is MOST important to complete before leaving?",o:["Updating the patient's dietary preferences","Documenting all medication administrations","Organizing the chart tabs","Writing a thank-you note to a patient's family"],c:[1],e:"Medication documentation is critical for patient safety. If medications are not documented, subsequent nurses may re-administer them, risking overdose. This aligns with the Right Documentation.",a:"B) Documenting all medication administrations",r:"6 Rights/Documentation"},
{id:88,s:"DO",t:"mc",q:"Which statement about HIPAA is CORRECT?",o:["HIPAA only applies to electronic records, not paper","HIPAA allows sharing PHI with anyone who asks","HIPAA protects all forms of patient health information","HIPAA is a state law that varies by location"],c:[2],e:"HIPAA is a FEDERAL law that protects ALL forms of PHI — electronic, paper, and oral. It applies to all healthcare providers, health plans, and healthcare clearinghouses nationwide.",a:"C) HIPAA protects all forms of patient health information",r:"HIPAA"},
{id:89,s:"DO",t:"mc",q:"During a handoff report using SBAR, the nurse states: 'Mrs. Johnson was admitted two days ago for pneumonia and has a history of COPD.' This is an example of which SBAR component?",o:["Situation","Background","Assessment","Recommendation"],c:[1],e:"Background includes pertinent medical history and clinical context. The admission reason and past medical history (COPD) provide background information for the receiving nurse.",a:"B) Background",r:"SBAR"},
{id:90,s:"DO",t:"order",q:"Arrange the steps for correcting a documentation error in a paper chart in the correct order:",o:["Draw a single line through the error","Write 'error' near the correction","Add your initials","Add the date and time"],c:[0,1,2,3],e:"The correct sequence: (1) Draw single line through error (keeps original legible), (2) Write 'error,' (3) Add your initials, (4) Add date and time. Never erase or use white-out.",a:"Single line → Write 'error' → Initials → Date/time",r:"Correcting Errors"},
{id:91,s:"DO",t:"tf",q:"True or False: Verbal orders should be used routinely to improve efficiency in medication administration.",o:["True","False"],c:[1],e:"False. Verbal orders should be reserved for EMERGENCY situations only. They increase the risk of errors. When used, the nurse must read back and verify the order with the prescriber.",a:"B) False",r:"Verbal Orders"},
{id:92,s:"DO",t:"mc",q:"A nurse accidentally administers the wrong medication to a patient. Which documentation should include this event?",o:["Only the nursing care plan","Only the patient's medical record","Both an incident report and the patient's medical record (regarding patient assessment and interventions)","Neither — it should only be verbally reported"],c:[2],e:"The patient's chart should document the assessment findings and interventions taken. An incident report (separate from the chart) documents the event for quality improvement. Both are needed.",a:"C) Both an incident report and the patient's medical record",r:"Incident Reports"},
{id:93,s:"DO",t:"mc",q:"Which technology is MOST useful for verifying the 'Right Patient' and 'Right Drug' at the bedside?",o:["Fax machine","Barcode medication administration (BCMA)","Telephone order system","Paper medication administration record"],c:[1],e:"Barcode medication administration (BCMA) scans the patient's wristband and the medication barcode to verify the right patient and right drug at the point of care, reducing medication errors.",a:"B) Barcode medication administration (BCMA)",r:"Barcode Scanning"},
{id:94,s:"PH",t:"mc",q:"A patient asks why their healthcare provider monitors peak and trough levels for their antibiotic. The nurse's BEST response is:",o:["'We check to see if the drug tastes right.'","'Peak and trough levels help ensure the drug is effective without being toxic.'","'We only check these for controlled substances.'","'These levels determine if you are allergic to the drug.'"],c:[1],e:"Peak levels confirm the drug reaches a therapeutic concentration. Trough levels ensure the drug doesn't accumulate to toxic levels. Together, they maintain the therapeutic range and prevent toxicity.",a:"B) 'Peak and trough levels help ensure the drug is effective without being toxic.'",r:"Peak and Trough Levels"},
{id:95,s:"PH",t:"tf",q:"True or False: Aspirin is classified as an anticoagulant like warfarin.",o:["True","False"],c:[1],e:"False. Aspirin is an ANTIPLATELET agent (it inhibits platelet aggregation). Warfarin is an ANTICOAGULANT (it inhibits vitamin K-dependent clotting factors). They work through different mechanisms.",a:"B) False",r:"Key Drugs"},
{id:96,s:"PH",t:"mc",q:"Which patient should the nurse assess FIRST after receiving shift report?",o:["A patient with a blood pressure of 128/78 on lisinopril","A patient on warfarin with an INR of 6.5 and gum bleeding","A patient on acetaminophen with a headache rated 3/10","A patient on a multivitamin who missed the morning dose"],c:[1],e:"An INR of 6.5 (therapeutic range 2-3) with active bleeding indicates serious warfarin toxicity. This patient is at risk for hemorrhage and needs immediate assessment and possible vitamin K administration.",a:"B) A patient on warfarin with an INR of 6.5 and gum bleeding",r:"Key Drugs"},
{id:97,s:"PH",t:"sata",q:"Which are correct regarding medication administration and the 6 Rights? (Select all that apply)",o:["Check the patient's identity with two identifiers","Verify the correct drug against the order","Administer at the right time","Document after administration","Skip documentation if the unit is busy"],c:[0,1,2,3],e:"All 6 Rights must be followed: Right Patient (two identifiers), Right Drug, Right Dose, Right Route, Right Time, and Right Documentation. Documentation should NEVER be skipped regardless of workload.",a:"A, B, C, D) Check identity, verify drug, right time, document after",r:"6 Rights"},
{id:98,s:"DO",t:"fib",q:"The SBAR handoff communication tool stands for Situation, Background, Assessment, and __________.",o:[],c:["Recommendation"],e:"SBAR = Situation, Background, Assessment, Recommendation. The 'R' is for Recommendation — what the nurse suggests should happen next for the patient's care.",a:"Recommendation",r:"SBAR"},
{id:99,s:"DO",t:"order",q:"Arrange the components of a problem-oriented medical record in the correct order:",o:["Database","Problem list","Plan","Progress notes"],c:[0,1,2,3],e:"Problem-oriented medical records follow: Database (comprehensive patient data) → Problem List (identified issues) → Plan (interventions for each problem) → Progress Notes (ongoing evaluation).",a:"Database → Problem list → Plan → Progress notes",r:"Medical Records"},
{id:100,s:"DO",t:"order",q:"Arrange the SBAR components in the correct order for a handoff report:",o:["Situation","Background","Assessment","Recommendation"],c:[0,1,2,3],e:"SBAR handoff: Situation (what's happening now) → Background (relevant history) → Assessment (your clinical judgment) → Recommendation (suggested next steps). This standardized format improves patient safety.",a:"Situation → Background → Assessment → Recommendation",r:"SBAR"}
];
export const QUESTIONS_PHARM = R.map(q => ({...q, section: S[q.s], type: q.t, options: q.o || [], correct: q.c, explanation: q.e, correctAnswer: q.a, ref: q.r, stem: q.q}));
export const SECTIONS_PHARM = Object.values(S);
export const COLORS_PHARM = {"Pharmacology":"#f59e0b","Documentation & Informatics":"#10b981"};
